VALUES
  ('dietitian-moex-11364', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列何者是最不可能經由食物或飲用水傳染的「病毒（virus）」： A型肝炎病毒（hepatitis A virus）  若瓦克病毒（Norwalk virus） 小兒麻痺病毒（poliomyelitis virus）  疹病毒（herpes virus） （請接背面） 九十三年第二次專門職業及技術人員高等暨普通考試醫事人員、  全一張 中醫師、心理師、呼吸治療師、營養師、獸醫人員考試試題 (背面) 類    科： 營養師', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11365', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '「旅行者腹瀉（Travelers’ diarrhea）」是由那種微生物所引起？ Pathogenic Escherichis coli  Bacillus cereus  Staphylococcus aureus  Listeria monocytogenes', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11366', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關食物中「硫代配醣體（glucosinolate）」的敘述，何者不正確？ 主要存在於十字花科的植物中  其經酵素分解後產生的代謝物具有毒性 分解硫代配醣體的酵素無法以加熱破壞  可能造成甲狀腺功能受損', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11367', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '「黃麴毒素（aflatoxins）」中，毒性最強的是： B1  G1  M1  B2', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11368', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '以懷孕動物進行的毒性試驗是： 致突變性試驗（mutagenicity test）  慢性毒性試驗（chronic toxicity test） 致癌性試驗（carcinogenicity test）  致畸胎性試驗（teratogenicity test）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11369', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '可抑制「含氮亞硝基化合物（N-nitroso compounds）」產生的物質是： 甲醛  維生素E  鹵素離子  硫氰酸根離子', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11370', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關食品中「多環芳香族碳氫化合物（polycyclic aromatic hydrocarbons）」的敘述，何者不正確？ 是全部由碳原子與氫原子所構成的化合物  蔬菜水果中不會含有 煙燻食品中含有    為致癌物', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11371', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '「IQ類化合物」是何種食品成分加熱後所產生的有毒熱分解產物？ 蛋白質  脂肪  維生素  礦物質', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11372', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關「食品標示」之敘述，下列何者不正確？ 重量以公克、公斤標示 容量以公升、毫升標示 液汁與固形物混合者以總重量標示 內容物為兩種或兩種以上時，應依其含量多寡由高至低標示', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
